static void TrainModel(string dataPath, string modelPath)
{
    var mlContext = new MLContext(seed: 42);

    // Load raw CSV and map "Yes"/"No" → boolean Label before training
    var rawData = mlContext.Data.LoadFromTextFile<ChurnRawInput>(
        dataPath, hasHeader: true, separatorChar: ',');

    var trainingRows = mlContext.Data
        .CreateEnumerable<ChurnRawInput>(rawData, reuseRowObject: false)
        .Select(row => new ChurnTrainingRow
        {
            Age = row.Age,
            Income = row.Income,
            Region = row.Region,
            PurchaseHistory = row.PurchaseHistory,
